//FOR PROBLEM 2
         public double VolumeOfCylinder(){
             return 3.142*radi*radi*Height;  // in place of 3.142 which is apprx value of PI we can use Math.PI which gives more accurate value of PI
    }

    public double surfaceArea(){
             return 2*3.142*radi*radi + 2*3.142*radi*Height;
    }
