class Rectangle1 {
    int length;
    int breadth;

    public Rectangle1() {
        this.length = 4;
        this.breadth = 7;
    }

    public Rectangle1(int length, int breadth) {
        this.length = length;
        this.breadth = breadth;
    }

    public int getLength() {
        return length;
    }

    public int getBreadth() {
        return breadth;
    }
}
